#!/bin/bash
# Check if a branch name was provided as an argument, otherwise exit with error message and usage information
if [ -z "$1" ]; then
    echo "Error: No arguments supplied." 2>&1;
    echo "\nUsage:\ $0 <branch_name> <script.sh file path (optional)>";
    exit 99; # Exit with error code of 'no args' and print usage information to stderr, then return from function call in bash scripting language as a result if the above condition is not met ie., no branch name was provided or it wasn’t supplied. The $0 represents current shell (script).
fi  # End checking for argument presence  
BRANCH=$1; shift    # Shift all arguments into BRANCH variable, excluding first one which should be the script's own path and options to handle multiple branches in future if needed by other scripts. This is done so that we can pass branch names as command line parameters when calling this bash file from another shell or a different process
# Checkout code with provided name – git checkout $BRANCH && git pull origin $BRANCH; where BRANCH comes directly into the commands for flexibility and ease of use. This is done so that we can pass branch names as command line parameters when calling this bash file from another shell or a different process
git checkout "${BRANCH}" 2>/dev/null && git pull origin $(echo "${BRANCH}") || ( echo 'Error: Invalid Branch' ; exit -1 ) # This is done to handle any errors that might occur during the execution of these commands.